/**
 * Progress Widget Component
 * 
 * Displays visual progress indication with status
 * Demonstrates computed signals for percentage calculations
 */

import { Component, input, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ProgressWidgetData } from '../../models/widget.model';

@Component({
  selector: 'app-progress-widget',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="widget progress-widget" [class]="statusClass()">
      <div class="widget-header">
        <span class="widget-label">{{ data().label }}</span>
        @if (data().showPercentage) {
          <span class="widget-percentage">{{ percentage() }}%</span>
        }
      </div>
      
      <div class="progress-bar">
        <div 
          class="progress-fill" 
          [class]="statusClass()"
          [style.width.%]="percentage()">
        </div>
      </div>

      <div class="widget-footer">
        <span class="widget-value">{{ data().value }} / {{ data().max }}</span>
        @if (data().tooltip) {
          <span class="widget-tooltip">{{ data().tooltip }}</span>
        }
      </div>
    </div>
  `,
  styles: [`
    .widget {
      padding: 16px;
      border-radius: 8px;
      background: white;
      border: 1px solid #ddd;
      min-width: 250px;
    }

    .widget-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 8px;
    }

    .widget-label {
      font-size: 0.875rem;
      color: #666;
      font-weight: 500;
    }

    .widget-percentage {
      font-size: 1.25rem;
      font-weight: bold;
    }

    .progress-bar {
      height: 8px;
      background: #f5f5f5;
      border-radius: 4px;
      overflow: hidden;
      margin-bottom: 8px;
    }

    .progress-fill {
      height: 100%;
      transition: width 0.3s ease;
      border-radius: 4px;
    }

    .widget-footer {
      display: flex;
      justify-content: space-between;
      align-items: center;
      font-size: 0.75rem;
      color: #999;
    }

    /* Status-based coloring */
    .status-success .widget-percentage {
      color: #4caf50;
    }

    .status-success .progress-fill {
      background: #4caf50;
    }

    .status-warning .widget-percentage {
      color: #ff9800;
    }

    .status-warning .progress-fill {
      background: #ff9800;
    }

    .status-error .widget-percentage {
      color: #f44336;
    }

    .status-error .progress-fill {
      background: #f44336;
    }

    .status-neutral .widget-percentage {
      color: #9e9e9e;
    }

    .status-neutral .progress-fill {
      background: #9e9e9e;
    }
  `],
})
export class ProgressWidgetComponent {
  /**
   * Input signal for widget data
   */
  data = input.required<ProgressWidgetData>();

  /**
   * Computed signal for percentage calculation
   */
  percentage = computed(() => {
    const { value, max } = this.data();
    if (max === 0) return 0;
    return Math.round((value / max) * 100);
  });

  /**
   * Computed signal for status CSS class
   */
  statusClass = computed(() => {
    return `status-${this.data().status}`;
  });
}

