/**
 * Task Count Widget Component
 * 
 * Displays a count with status coloring
 * Demonstrates signal-based derived state from store
 */

import { Component, input, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TaskCountWidgetData } from '../../models/widget.model';

@Component({
  selector: 'app-task-count-widget',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="widget task-count-widget" [class]="statusClass()">
      <div class="widget-icon">
        {{ data().icon || '📊' }}
      </div>
      <div class="widget-content">
        <div class="widget-label">{{ data().label }}</div>
        <div class="widget-value">{{ data().value }}</div>
      </div>
      @if (data().tooltip) {
        <div class="widget-tooltip">{{ data().tooltip }}</div>
      }
    </div>
  `,
  styles: [`
    .widget {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 16px;
      border-radius: 8px;
      background: white;
      border: 1px solid #ddd;
      min-width: 200px;
    }

    .widget-icon {
      font-size: 2rem;
    }

    .widget-content {
      flex: 1;
    }

    .widget-label {
      font-size: 0.875rem;
      color: #666;
      margin-bottom: 4px;
    }

    .widget-value {
      font-size: 1.5rem;
      font-weight: bold;
    }

    .widget-tooltip {
      font-size: 0.75rem;
      color: #999;
    }

    /* Status-based styling */
    .status-success {
      border-left: 4px solid #4caf50;
    }

    .status-success .widget-value {
      color: #4caf50;
    }

    .status-warning {
      border-left: 4px solid #ff9800;
    }

    .status-warning .widget-value {
      color: #ff9800;
    }

    .status-error {
      border-left: 4px solid #f44336;
    }

    .status-error .widget-value {
      color: #f44336;
    }

    .status-neutral {
      border-left: 4px solid #9e9e9e;
    }

    .status-neutral .widget-value {
      color: #9e9e9e;
    }
  `],
})
export class TaskCountWidgetComponent {
  /**
   * Input signal for widget data
   */
  data = input.required<TaskCountWidgetData>();

  /**
   * Computed signal for status CSS class
   */
  statusClass = computed(() => {
    return `status-${this.data().status}`;
  });
}

