/**
 * Task Card Component
 * 
 * Demonstrates:
 * 1. Input signals for receiving data
 * 2. Computed signals for derived/transformed values
 * 3. Local UI state with signals
 * 4. Signal-based reactivity
 */

import { Component, input, signal, computed, output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Task } from '../../models/board.model';

@Component({
  selector: 'app-task-card',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="task-card" [class]="priorityClass()">
      <div class="task-header">
        <h3>{{ task().title }}</h3>
        <button (click)="toggleExpanded()">
          {{ isExpanded() ? '▼' : '▶' }}
        </button>
      </div>

      @if (isExpanded()) {
        <div class="task-details">
          <p>{{ task().description || 'No description' }}</p>
          <div class="task-meta">
            <span class="priority" [class]="priorityClass()">
              {{ task().priority }}
            </span>
            @if (task().assignee) {
              <span class="assignee">{{ task().assignee }}</span>
            }
            <span class="date">{{ formattedDate() }}</span>
            @if (isOverdue()) {
              <span class="overdue-badge">⚠️ Overdue</span>
            }
          </div>
        </div>
      }

      <div class="task-actions">
        <button (click)="onEdit()">Edit</button>
        <button (click)="onDelete()">Delete</button>
      </div>
    </div>
  `,
  styles: [`
    .task-card {
      border: 1px solid #ddd;
      border-radius: 8px;
      padding: 12px;
      margin-bottom: 8px;
      background: white;
    }

    .task-card.priority-low { border-left: 4px solid #4caf50; }
    .task-card.priority-medium { border-left: 4px solid #ff9800; }
    .task-card.priority-high { border-left: 4px solid #f44336; }
    .task-card.priority-critical { border-left: 4px solid #9c27b0; }

    .task-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .task-details {
      margin-top: 8px;
      padding-top: 8px;
      border-top: 1px solid #eee;
    }

    .task-meta {
      display: flex;
      gap: 8px;
      margin-top: 8px;
      font-size: 0.875rem;
    }

    .priority {
      padding: 2px 8px;
      border-radius: 4px;
      font-weight: bold;
    }

    .priority-low { background: #e8f5e9; color: #2e7d32; }
    .priority-medium { background: #fff3e0; color: #e65100; }
    .priority-high { background: #ffebee; color: #c62828; }
    .priority-critical { background: #f3e5f5; color: #6a1b9a; }

    .overdue-badge {
      background: #ffcdd2;
      color: #c62828;
      padding: 2px 8px;
      border-radius: 4px;
    }

    .task-actions {
      display: flex;
      gap: 8px;
      margin-top: 8px;
    }

    button {
      padding: 4px 12px;
      border: 1px solid #ddd;
      border-radius: 4px;
      background: white;
      cursor: pointer;
    }

    button:hover {
      background: #f5f5f5;
    }
  `],
})
export class TaskCardComponent {
  /**
   * Input signal - receives task data from parent
   */
  task = input.required<Task>();

  /**
   * Output signals - emit events to parent
   */
  edit = output<Task>();
  delete = output<string>();

  /**
   * Local UI state - managed with signals
   * This is component-level state, not stored in NgRx
   */
  isExpanded = signal(false);
  isEditMode = signal(false);

  /**
   * Computed signal - CSS class based on priority
   * Automatically recomputes when task() changes
   */
  priorityClass = computed(() => {
    return `priority-${this.task().priority}`;
  });

  /**
   * Computed signal - formatted date
   * TODO: Implement proper date formatting
   */
  formattedDate = computed(() => {
    const date = this.task().updatedAt;
    // TODO: Use date-fns or Intl.DateTimeFormat for better formatting
    return new Date(date).toLocaleDateString();
  });

  /**
   * Computed signal - check if task is overdue
   * TODO: Implement if you add dueDate to Task model
   */
  isOverdue = computed(() => {
    // TODO: Compare task.dueDate with current date
    // const dueDate = this.task().dueDate;
    // return dueDate && new Date(dueDate) < new Date();
    return false;
  });

  /**
   * Toggle expansion state
   */
  toggleExpanded() {
    this.isExpanded.update((expanded) => !expanded);
  }

  /**
   * Emit edit event
   */
  onEdit() {
    this.edit.emit(this.task());
  }

  /**
   * Emit delete event
   */
  onDelete() {
    this.delete.emit(this.task().id);
  }
}

/**
 * Signal patterns demonstrated:
 * 
 * 1. input() - Reactive inputs from parent
 * 2. output() - Type-safe event emitters
 * 3. signal() - Local mutable state
 * 4. computed() - Derived state that auto-updates
 * 
 * Benefits:
 * - Automatic change detection
 * - No manual subscription management
 * - Clear data flow
 * - Type-safe
 */
