/**
 * Dynamic Widget Outlet Directive
 * 
 * Enables dynamic component rendering with:
 * 1. Single or array of component configurations
 * 2. Dynamic input passing (static values, Observables, Signals)
 * 3. Output event handling
 * 4. Proper lifecycle management
 * 5. Subscription cleanup
 */

import {
  Directive,
  Input,
  ViewContainerRef,
  ComponentRef,
  OnInit,
  OnDestroy,
  Type,
  inject,
  Signal,
  effect,
  Injector,
} from '@angular/core';
import { Observable, Subscription } from 'rxjs';

/**
 * Configuration interface for dynamic components
 * Uses generics for type safety
 */
export interface WidgetConfig<T = any> {
  component: Type<T>;
  inputs?: {
    [key: string]: any | Observable<any> | Signal<any>;
  };
  outputs?: {
    [key: string]: (event: any) => void;
  };
}

/**
 * Dynamic Widget Outlet Directive
 * 
 * Usage:
 * <ng-container *dynamicWidgetOutlet="widgetConfig"></ng-container>
 * 
 * Or with array:
 * <ng-container *dynamicWidgetOutlet="widgetConfigs"></ng-container>
 */
@Directive({
  selector: '[dynamicWidgetOutlet]',
  standalone: true,
})
export class DynamicWidgetOutletDirective implements OnInit, OnDestroy {
  private viewContainerRef = inject(ViewContainerRef);
  private injector = inject(Injector);

  /**
   * Accept single config or array of configs
   */
  @Input() dynamicWidgetOutlet!: WidgetConfig | WidgetConfig[];

  /**
   * Store component references for cleanup
   */
  private componentRefs: ComponentRef<any>[] = [];

  /**
   * Store subscriptions for cleanup
   */
  private subscriptions: Subscription[] = [];

  ngOnInit() {
    this.renderComponents();
  }

  ngOnDestroy() {
    this.cleanup();
  }

  /**
   * Render components based on configuration
   */
  private renderComponents() {
    // Clear existing components
    this.cleanup();
    this.viewContainerRef.clear();

    // Handle single or array of configs
    const configs = Array.isArray(this.dynamicWidgetOutlet)
      ? this.dynamicWidgetOutlet
      : [this.dynamicWidgetOutlet];

    // Render each component
    configs.forEach((config) => {
      this.renderComponent(config);
    });
  }

  /**
   * Render a single component
   * 
   * Implementation:
   * 1. Create component using ViewContainerRef.createComponent()
   * 2. Set inputs (handle static, Observable, and Signal types)
   * 3. Subscribe to outputs and call handlers
   * 4. Store ComponentRef and Subscriptions for cleanup
   */
  private renderComponent(config: WidgetConfig) {
    // 1. Create component instance dynamically
    const componentRef = this.viewContainerRef.createComponent(config.component, {
      injector: this.injector
    });
    
    // Store reference for cleanup
    this.componentRefs.push(componentRef);

    // 2. Set inputs (handle different input types)
    if (config.inputs) {
      Object.entries(config.inputs).forEach(([key, value]) => {
        if (this.isObservable(value)) {
          // Subscribe to Observable and update input dynamically
          const sub = value.subscribe((val) => {
            componentRef.setInput(key, val);
          });
          this.subscriptions.push(sub);
        } else if (this.isSignal(value)) {
          // Use effect to watch Signal and update input reactively
          const effectRef = effect(() => {
            const signalValue = value();
            componentRef.setInput(key, signalValue);
          }, { injector: this.injector });
          
          // Note: Effects are automatically cleaned up when injector is destroyed
        } else {
          // Set static value directly
          componentRef.setInput(key, value);
        }
      });
    }

    // 3. Subscribe to outputs and call handlers
    if (config.outputs) {
      Object.entries(config.outputs).forEach(([key, handler]) => {
        const output = componentRef.instance[key];
        
        // Check if output exists and is subscribable (EventEmitter)
        if (output && typeof output.subscribe === 'function') {
          const sub = output.subscribe((event: any) => {
            handler(event);
          });
          this.subscriptions.push(sub);
        }
      });
    }
  }

  /**
   * Type guards for input types
   */
  private isObservable(value: any): value is Observable<any> {
    return value && typeof value.subscribe === 'function';
  }

  private isSignal(value: any): value is Signal<any> {
    // Signals don't have a standard type guard yet
    // Check for common Signal properties
    return value && typeof value === 'function' && 'subscribe' in value;
  }

  /**
   * Cleanup all components and subscriptions
   */
  private cleanup() {
    // Unsubscribe from all subscriptions
    this.subscriptions.forEach((sub) => sub.unsubscribe());
    this.subscriptions = [];

    // Destroy all component references
    this.componentRefs.forEach((ref) => ref.destroy());
    this.componentRefs = [];
  }
}

/**
 * Implementation notes:
 * 
 * 1. ViewContainerRef.createComponent() - Creates component dynamically
 * 2. ComponentRef.setInput() - Sets input values
 * 3. ComponentRef.instance - Access component instance for outputs
 * 4. Store references for proper cleanup
 * 
 * Lifecycle management:
 * - Create: ngOnInit
 * - Update: When inputs change (use effect for Signals)
 * - Destroy: ngOnDestroy (cleanup subscriptions and component refs)
 * 
 * Memory leak prevention:
 * - Always unsubscribe from Observables
 * - Always destroy ComponentRefs
 * - Clear ViewContainerRef
 */
